MRFCircumVentRefinementCmd::MRFCircumVentRefinementCmd() :
CATStateCommand ("MRFCircumVentRefinementCmd", CATDlgEngOneShot, CATCommandModeExclusive)
//  Valid states are CATDlgEngOneShot and CATDlgEngRepeat
, _pMRFCircumVentRefCmdDlg(NULL)
, _pPathElementAgentForGeomSet(NULL)
, _pDialogAgentForGeomSet(NULL)
, _pPathElementForGeomSet(NULL)
,_pPathElementForVentsGeomSet(NULL)
,_pPathElementForCircumVentGeomSet(NULL)
, _pHSO(NULL)
, _pEditor(NULL)
, _spGeomSet(NULL_var)
, _spVentGeomSet(NULL_var)
, _spCircumVentGeomSet(NULL_var)
, _pCircumVentCollecvtion(NULL)
, _pMultiListValuesToSet(NULL)
, _pMRFCircumVentRefinementOperations(NULL)
, _spBackProfileSurface(NULL)
, _spAnalysisGeomSet(NULL_var)
,_spMergedVentProfilesGeomSet(NULL_var)
,_spLateralVentProfilesGeomSet(NULL_var)
,_pDialogAgentForVentGeomSet(NULL)
,_pDialogAgentForCircumVetnGeomSet(NULL)
{
	_pMRFCircumVentRefinementOperations = new MRFCircumVentRefinementOperations();

	_pEditor = CATFrmEditor::GetCurrentEditor();
	if (NULL != _pEditor)
	{
		_pHSO = _pEditor->GetHSO();
	}

	_pListOfCircumVentCollStruct.RemoveAll();
	_pListOfMultiListValuesToSetStruct.RemoveAll();
	_mapRevolve.clear();

	_isPreviewClicked = false;
}
//-------------------------------------------------------------------------
// Destructor
//-------------------------------------------------------------------------
MRFCircumVentRefinementCmd::~MRFCircumVentRefinementCmd()
{
	if (_pMRFCircumVentRefCmdDlg)
		_pMRFCircumVentRefCmdDlg->RequestDelayedDestruction(); _pMRFCircumVentRefCmdDlg = NULL;

	if (_pPathElementAgentForGeomSet)
		_pPathElementAgentForGeomSet->RequestDelayedDestruction(); _pPathElementAgentForGeomSet = NULL;

	if (_pDialogAgentForGeomSet)
		_pDialogAgentForGeomSet->RequestDelayedDestruction(); _pDialogAgentForGeomSet = NULL;

	if (_pDialogAgentForVentGeomSet)
		_pDialogAgentForVentGeomSet->RequestDelayedDestruction(); _pDialogAgentForVentGeomSet = NULL;

	if (_pDialogAgentForCircumVetnGeomSet)
		_pDialogAgentForCircumVetnGeomSet->RequestDelayedDestruction(); _pDialogAgentForCircumVetnGeomSet = NULL;

	if (_pPathElementForGeomSet)
		_pPathElementForGeomSet = NULL;


	if (_pPathElementForVentsGeomSet)
			_pPathElementForVentsGeomSet = NULL;
	
	if (_pPathElementForCircumVentGeomSet)
		_pPathElementForCircumVentGeomSet = NULL;

	if (NULL != _pHSO && !_pHSO->IsNull())
	{
		_pHSO->Empty();
		_pHSO = NULL;
	}

	if (_pEditor != NULL)
		_pEditor = NULL;

	if (!!_spGeomSet)
		_spGeomSet->Release(); _spGeomSet = NULL;

	if (!!_spVentGeomSet)
		_spVentGeomSet->Release(); _spVentGeomSet = NULL;
	
	if (!!_spCircumVentGeomSet)
		_spCircumVentGeomSet->Release(); _spCircumVentGeomSet = NULL;

	//if (_pCircumVentCollecvtion)
	//	delete _pCircumVentCollecvtion; _pCircumVentCollecvtion = NULL;
	//
	//if (_pMultiListValuesToSet)
	//	delete _pMultiListValuesToSet; _pMultiListValuesToSet = NULL;

	if (_pListOfCircumVentCollStruct.Size() > 0)
	{
		for (int i = 1; i <= _pListOfCircumVentCollStruct.Size(); i++)
		{
			CircumVentCollection *pOnCircumVent = (CircumVentCollection*)_pListOfCircumVentCollStruct[i];
			if (pOnCircumVent)
				delete pOnCircumVent; pOnCircumVent = NULL;
		}
	}

	_pListOfCircumVentCollStruct.RemoveAll();

	if (_pListOfMultiListValuesToSetStruct.Size() > 0)
	{
		for (int i = 1; i <= _pListOfMultiListValuesToSetStruct.Size(); i++)
		{
			MultiListValuesToSet *pOnMultiListValToSet = (MultiListValuesToSet*)_pListOfMultiListValuesToSetStruct[i];
			delete pOnMultiListValToSet; pOnMultiListValToSet = NULL;
		}
	}

	_pListOfMultiListValuesToSetStruct.RemoveAll();

	_mapRevolve.clear();

	if (!!_spBackProfileSurface)
		_spBackProfileSurface->Release(); _spBackProfileSurface = NULL;
	
	if (_pMRFCircumVentRefinementOperations)
		_pMRFCircumVentRefinementOperations->Release(); _pMRFCircumVentRefinementOperations = NULL;

	if (_spAnalysisGeomSet)
		_spAnalysisGeomSet->Release(); _spAnalysisGeomSet = NULL_var;
	
	if (_spMergedVentProfilesGeomSet)
		_spMergedVentProfilesGeomSet->Release(); _spMergedVentProfilesGeomSet = NULL_var;
	
	if (_spLateralVentProfilesGeomSet)
		_spLateralVentProfilesGeomSet->Release(); _spLateralVentProfilesGeomSet = NULL_var;

}


//-------------------------------------------------------------------------
// BuildGraph()
//-------------------------------------------------------------------------
void MRFCircumVentRefinementCmd::BuildGraph()
{
	_pMRFCircumVentRefCmdDlg = new MRFCircumVentRefinementCmdDlg();
	_pMRFCircumVentRefCmdDlg->Build();
	_pMRFCircumVentRefCmdDlg->SetVisibility(CATDlgShow);
	CATDlgContextualMenu* contextMenuClearSelectionGeomSet = _pMRFCircumVentRefCmdDlg->GetContextualMenu();
	if (contextMenuClearSelectionGeomSet)
		AddAnalyseNotificationCB(contextMenuClearSelectionGeomSet, contextMenuClearSelectionGeomSet->GetVisibilityNotification(), (CATCommandMethod)&MRFCircumVentRefinementCmd::OnContextMenuSelected, "FromVentSetSelectorList");

	_pPathElementAgentForGeomSet = new CATPathElementAgent("GeomSetSelectionPathElemAgent");
	if (_pPathElementAgentForGeomSet)
	{
		CATListOfCATString ListSurfaces;
		ListSurfaces.Append("CATIBodyRequest");

		_pPathElementAgentForGeomSet->SetOrderedTypeList(ListSurfaces);
		_pPathElementAgentForGeomSet->SetBehavior(CATDlgEngWithPrevaluation | CATDlgEngRepeat | CATDlgEngWithPSO);

	}

	_pDialogAgentForGeomSet = new CATDialogAgent("BackProfileGeomSetDialogAgent");
	if (_pDialogAgentForGeomSet)
	{
		CATDlgSelectorList* pSelectorListBackProfileGeomSet = _pMRFCircumVentRefCmdDlg->GetSelectorListGeomSet();

		if (NULL != pSelectorListBackProfileGeomSet)
		{
			_pDialogAgentForGeomSet->AcceptOnNotify(pSelectorListBackProfileGeomSet, pSelectorListBackProfileGeomSet->GetListSelectNotification());
		}
	}


	CATDlgPushButton *pPushButtonMerge = _pMRFCircumVentRefCmdDlg->GetPushButtonMerge();
	if (pPushButtonMerge)
	{
		AddAnalyseNotificationCB(pPushButtonMerge, pPushButtonMerge->GetPushBActivateNotification(), (CATCommandMethod)&MRFCircumVentRefinementCmd::OnPushButtonMergeClicked, NULL);
	}
	
	CATDlgPushButton *pPushButtonLateral = _pMRFCircumVentRefCmdDlg->GetPushButtonLateral();
	if (pPushButtonLateral)
	{
		AddAnalyseNotificationCB(pPushButtonLateral, pPushButtonLateral->GetPushBActivateNotification(), (CATCommandMethod)&MRFCircumVentRefinementCmd::OnPushButtonLateralClicked, NULL);
	}

	CATDlgPushButton *pPushButtonAnalyse = _pMRFCircumVentRefCmdDlg->GetPushButtonAnalyseRevolve();
	if (pPushButtonLateral)
	{
		AddAnalyseNotificationCB(pPushButtonAnalyse, pPushButtonAnalyse->GetPushBActivateNotification(), (CATCommandMethod)&MRFCircumVentRefinementCmd::OnPushButtonAnalyseRevolveClicked, NULL);
	}

	CATDlgMultiList* pMultiList = _pMRFCircumVentRefCmdDlg->GetMultiListCircumVentSetCollection();
	if (pMultiList)
	{
		AddAnalyseNotificationCB(pMultiList, pMultiList->GetListSelectNotification(), (CATCommandMethod)&MRFCircumVentRefinementCmd::OnMultiListSelected, NULL);
	}

	CATDlgPushButton *ppushButtonReset = _pMRFCircumVentRefCmdDlg->GetPushButtonReset();
	if (ppushButtonReset)
	{
		AddAnalyseNotificationCB(ppushButtonReset, ppushButtonReset->GetPushBActivateNotification(), (CATCommandMethod)&MRFCircumVentRefinementCmd::OnPushButtonResetClicked, NULL);
	}

	_pDialogAgentForVentGeomSet = new CATDialogAgent("VentGeomSetDialogAgent");
	if (_pDialogAgentForVentGeomSet)
	{
		CATDlgSelectorList* pSelectorListVentGeomSet = _pMRFCircumVentRefCmdDlg->GetSelectorListVentGeomSet();

		if (NULL != pSelectorListVentGeomSet)
		{
			_pDialogAgentForVentGeomSet->AcceptOnNotify(pSelectorListVentGeomSet, pSelectorListVentGeomSet->GetListSelectNotification());
		}
	}

	_pDialogAgentForCircumVetnGeomSet = new CATDialogAgent("CircumVentGeomSetDialogAgent");
	if (_pDialogAgentForCircumVetnGeomSet)
	{
		CATDlgSelectorList* pSelectorListCircumVentGeomSet = _pMRFCircumVentRefCmdDlg->GetSelectorListCircumVentGeomSet();

		if (NULL != pSelectorListCircumVentGeomSet)
		{
			_pDialogAgentForCircumVetnGeomSet->AcceptOnNotify(pSelectorListCircumVentGeomSet, pSelectorListCircumVentGeomSet->GetListSelectNotification());
		}
	}

	AddAnalyseNotificationCB(_pMRFCircumVentRefCmdDlg, _pMRFCircumVentRefCmdDlg->GetDiaOKNotification(), (CATCommandMethod)& MRFCircumVentRefinementCmd::OnOK, NULL);
	AddAnalyseNotificationCB(_pMRFCircumVentRefCmdDlg, _pMRFCircumVentRefCmdDlg->GetDiaCANCELNotification(), (CATCommandMethod)& MRFCircumVentRefinementCmd::OnClose, NULL);
	AddAnalyseNotificationCB(_pMRFCircumVentRefCmdDlg, _pMRFCircumVentRefCmdDlg->GetWindCloseNotification(), (CATCommandMethod)& MRFCircumVentRefinementCmd::OnClose, NULL);
	AddAnalyseNotificationCB(_pMRFCircumVentRefCmdDlg, _pMRFCircumVentRefCmdDlg->GetDiaPREVIEWNotification(), (CATCommandMethod)& MRFCircumVentRefinementCmd::OnPreviewButtonClicked, "FromPreviewButton");


	CATDialogState *initialState = GetInitialState("InitialState");
	initialState->AddDialogAgent(_pDialogAgentForGeomSet);
	initialState->AddDialogAgent(_pDialogAgentForVentGeomSet);
	initialState->AddDialogAgent(_pDialogAgentForCircumVetnGeomSet);
	initialState->AddDialogAgent(_pPathElementAgentForGeomSet);

	CATDialogState *secondState = AddDialogState("VentGeomSetSelState");
	secondState->AddDialogAgent(_pDialogAgentForGeomSet);
	secondState->AddDialogAgent(_pDialogAgentForVentGeomSet);
	secondState->AddDialogAgent(_pDialogAgentForCircumVetnGeomSet);
	secondState->AddDialogAgent(_pPathElementAgentForGeomSet);
	
	CATDialogState *thirdState = AddDialogState("CircumVentGeomSetSelState");
	thirdState->AddDialogAgent(_pDialogAgentForGeomSet);
	thirdState->AddDialogAgent(_pDialogAgentForVentGeomSet);
	thirdState->AddDialogAgent(_pDialogAgentForCircumVetnGeomSet);
	thirdState->AddDialogAgent(_pPathElementAgentForGeomSet);

	//AddTransition(NULL, initialState, IsOutputSetCondition(_pDialogAgentForGeomSet), Action((ActionMethod)&MRFCircumVentRefinementCmd::OnSelectorListSelected));
	CATDlgSelectorList* pSelectorListBackProfileGeomSet = _pMRFCircumVentRefCmdDlg->GetSelectorListGeomSet();
	if (pSelectorListBackProfileGeomSet)
	{
		CATDialogTransition *pJoinTransitionForInitialState = AddTransition(initialState, initialState, IsOutputSetCondition(_pDialogAgentForGeomSet),
			Action((ActionMethod)&MRFCircumVentRefinementCmd::OnSelectorListSelected, NULL, NULL, pSelectorListBackProfileGeomSet));
		pJoinTransitionForInitialState->AddInitialState(secondState);
		pJoinTransitionForInitialState->AddInitialState(thirdState);

		AddTransition(initialState, initialState, IsOutputSetCondition(_pPathElementAgentForGeomSet),
			Action((ActionMethod)&MRFCircumVentRefinementCmd::OnGeomSetSelected, NULL, NULL, pSelectorListBackProfileGeomSet));

	}
	CATDlgSelectorList* pSelectorListVentGeomSet = _pMRFCircumVentRefCmdDlg->GetSelectorListVentGeomSet();

	if (pSelectorListVentGeomSet)
	{
		CATDialogTransition *pJoinTransitionForSecondState = AddTransition(secondState, secondState, IsOutputSetCondition(_pDialogAgentForVentGeomSet),
			Action((ActionMethod)&MRFCircumVentRefinementCmd::OnSelectorListSelected, NULL, NULL, pSelectorListVentGeomSet));
		pJoinTransitionForSecondState->AddInitialState(initialState);
		pJoinTransitionForSecondState->AddInitialState(thirdState);


		AddTransition(secondState, secondState, IsOutputSetCondition(_pPathElementAgentForGeomSet),
			Action((ActionMethod)&MRFCircumVentRefinementCmd::OnGeomSetSelected, NULL, NULL, pSelectorListVentGeomSet));

	}

	CATDlgSelectorList* pSelectorListCircumVentGeomSet = _pMRFCircumVentRefCmdDlg->GetSelectorListCircumVentGeomSet();

	if (pSelectorListCircumVentGeomSet)
	{
		CATCommandClientData pTemp(pSelectorListCircumVentGeomSet);

		CATDialogTransition *pJoinTransitionForThirdState = AddTransition(thirdState, thirdState, IsOutputSetCondition(_pDialogAgentForCircumVetnGeomSet),
			Action((ActionMethod)&MRFCircumVentRefinementCmd::OnSelectorListSelected, NULL, NULL, pSelectorListCircumVentGeomSet));
		pJoinTransitionForThirdState->AddInitialState(initialState);
		pJoinTransitionForThirdState->AddInitialState(secondState);

		//Selection State

		AddTransition(thirdState, thirdState, IsOutputSetCondition(_pPathElementAgentForGeomSet),
			Action((ActionMethod)&MRFCircumVentRefinementCmd::OnGeomSetSelected, NULL, NULL, pSelectorListCircumVentGeomSet));
	}


}

