//-----------------Function to clear existing selected reference surface or VentGeom Set when "Clear List" push item selected from contextual menu STARTS--------------//
void MRFCircumVentRefinementCmd::OnCtxMenuClearSelectorList(CATCommand * ipCommand, CATNotification * ipNotification, CATCommandClientData iUsefulData)
{
	char * pstrAction = (char *)iUsefulData;

	CATString strAction(pstrAction);

	CATDlgSelectorList* pSelectorListSourceSurface = NULL;


	if (NULL != _pHSO && NULL != _pPathElementForGeomSet && 0 != _pHSO->IsMember(_pPathElementForGeomSet))
	{
		_pHSO->RemoveElement(_pPathElementForGeomSet);
	}

	_pPathElementForGeomSet = NULL;

	pSelectorListSourceSurface = _pMRFCircumVentRefCmdDlg->GetSelectorListGeomSet();

	if (pSelectorListSourceSurface)
	{
		ClearAllSelections();
		pSelectorListSourceSurface->ClearSelect();
		pSelectorListSourceSurface->ClearLine();
		pSelectorListSourceSurface->SetLine("No Selection");
		_pMRFCircumVentRefCmdDlg->SetFocusOnSelectorList(pSelectorListSourceSurface);

	}

}
//-----------------Function to clear existing selected reference surface or VentGeom Set when "Clear List" push item selected from contextual menu ENDS--------------//

CATBoolean MRFCircumVentRefinementCmd::OnSelectorListSelected(void* iUsefulData)
{
	CATDlgSelectorList* pSelectorListVentGeomSet = NULL;
	CATDialogAgent *pDialogAgent = NULL;

	pSelectorListVentGeomSet = (CATDlgSelectorList*)iUsefulData;
	if (pSelectorListVentGeomSet == NULL)
		return false;
	CATPathElement *pPathElement = NULL;

	CATUnicodeString strString = SelctorListDefVal;
	if (!!_pMRFCircumVentRefCmdDlg)
	{
		_pMRFCircumVentRefCmdDlg->SetStatusBarText(strString);
		ClearAllSelections();

		CATUnicodeString selectorListName = pSelectorListVentGeomSet->GetName();
		if (selectorListName == SelctorList_BackProfGeomSet)
		{
			pDialogAgent = _pDialogAgentForGeomSet;
			pPathElement = _pPathElementForGeomSet;
		}
		else if (selectorListName == SelctorList_VentsGeomSet)
		{
			pDialogAgent = _pDialogAgentForVentGeomSet;
			pPathElement = _pPathElementForVentsGeomSet;


		}
		else if (selectorListName == SelctorList_CircumVentGeomSet)
		{
			pDialogAgent = _pDialogAgentForCircumVetnGeomSet;
			pPathElement = _pPathElementForCircumVentGeomSet;


		}

		if (NULL != pSelectorListVentGeomSet)
		{
			_pMRFCircumVentRefCmdDlg->SetFocusOnSelectorList(pSelectorListVentGeomSet);

		}

		if (NULL != _pHSO)
		{
			_pHSO->Empty();
			if (0 == _pHSO->IsMember(pPathElement))
			{
				_pHSO->AddElement(pPathElement);
			}
		}
	}
	if (!!pDialogAgent)
		pDialogAgent->InitializeAcquisition();

	return true;
}

CATBoolean MRFCircumVentRefinementCmd::OnGeomSetSelected(void* iUsefulData)
{
	CATDlgSelectorList *pSelecList = NULL;
	pSelecList = (CATDlgSelectorList*)iUsefulData;

	if (pSelecList == NULL)
		return false;

	CATUnicodeString surfaceAliasName;
	CATPathElement *pPathElement = NULL;
	 pPathElement = _pPathElementAgentForGeomSet->GetValue();

	CATBaseUnknown* pSelectedGeomSet = NULL;

	//CATIGSMTool_var spGSMTool;
	if (pPathElement)
	{
		// Add current selection to HSO if not added yet
		if (NULL != _pHSO && 0 == _pHSO->IsMember(pPathElement))
		{
			_pHSO->Empty();
			_pHSO->AddElement(pPathElement);
		}

		pSelectedGeomSet = pPathElement->CurrentElement(); // No need to release the returned object

		if (pSelectedGeomSet)
		{
			/*CATBoolean isSameCurve = CATFalse;
			if (_spGeomSet == NULL_var)
				_spGeomSet = pSelectedGeomSet;
			else if (_spGeomSet != NULL_var && !_spGeomSet->IsEqual(pSelectedGeomSet))
			{
				_spGeomSet->Release();
				_spGeomSet = NULL;
				_spGeomSet = pSelectedGeomSet;


			}
			else
				isSameCurve = CATTrue;*/

			//CATIAlias_var pAliasON3DCurve(pSelectedCurve);
			CATIAlias_var pAliasON3DCurve(pSelectedGeomSet);
			if (!!pAliasON3DCurve) {
				surfaceAliasName = pAliasON3DCurve->GetAlias();
			}
		}

		_pMRFCircumVentRefCmdDlg->SetSelectorListGeomSet(surfaceAliasName, pSelecList);


		CATUnicodeString selListName = pSelecList->GetName();
		if (selListName == SelctorList_BackProfGeomSet)
		{
			_pPathElementForGeomSet = pPathElement;
			pSelecList->GetName();
			_spGeomSet = pSelectedGeomSet;
			HRESULT rc = E_FAIL;
			if (_pMRFCircumVentRefinementOperations && !!_spGeomSet)
				rc = _pMRFCircumVentRefinementOperations->GetGSMUseFactoryFromFeature(_spGeomSet);
			if (SUCCEEDED(rc))
				this->ReadSelectedGeomSet(_spGeomSet);
			//if (SUCCEEDED(rc))
			//{
			//	spGSMTool = _spGeomSet;
			//	int modePrivete = -123;
			//	if (!!spGSMTool)
			//		spGSMTool->IsPrivate(modePrivete);
			//	if (modePrivete)
			//		spGSMTool->SetPrivate(0);
			//}
		}
		else if (selListName == SelctorList_VentsGeomSet)
		{
			_spVentGeomSet = pSelectedGeomSet;
			 _pPathElementForVentsGeomSet = pPathElement;

			 if(_pMRFCircumVentRefinementOperations)
				 _pMRFCircumVentRefinementOperations->GetGSMUseFactoryFromFeature(_spVentGeomSet);

			 this->GetListOfVentsUnderSelectedVentGeomSet(_spVentGeomSet); //Retriev 2DVents and 3DVents under a selected GeomSet



		}
		else if (selListName == SelctorList_CircumVentGeomSet)
		{
			_spCircumVentGeomSet = pSelectedGeomSet;
			_pPathElementForCircumVentGeomSet = pPathElement;


		}


	}

	_pPathElementAgentForGeomSet->InitializeAcquisition();

	return true;
}

void MRFCircumVentRefinementCmd::ClearAllSelections()
{
	if (_pMRFCircumVentRefCmdDlg)
	{
		_pMRFCircumVentRefCmdDlg->GetSelectorListGeomSet()->ClearSelect();
		_pMRFCircumVentRefCmdDlg->GetSelectorListVentGeomSet()->ClearSelect();
		_pMRFCircumVentRefCmdDlg->GetSelectorListCircumVentGeomSet()->ClearSelect();
		_pMRFCircumVentRefCmdDlg->GetMultiListCircumVentSetCollection()->ClearSelect();
	}
}


void MRFCircumVentRefinementCmd::ReadSelectedGeomSet(CATBaseUnknown_var spOnGeomSet)
{
	HRESULT hr = E_FAIL;

	CATApplicationFrame * pAppFrame = CATApplicationFrame::GetFrame();
	if (NULL == pAppFrame)
		return;

	CATDlgWindow * pMainWindow = pAppFrame->GetMainWindow();
	if (NULL == pMainWindow)
		return;


	CATListValCATBaseUnknown_var ListResults, listOfCircumGeomSet;

	CATIBodyRequest * pCurBody = NULL;
	if (spOnGeomSet != NULL_var)
	{
		CATIGSMTool_var spGSMToolOnSelGeomSet = spOnGeomSet;
		int isOrderedGeoSet;
		if (!!spGSMToolOnSelGeomSet)
			spGSMToolOnSelGeomSet->GetType(isOrderedGeoSet);

		if (isOrderedGeoSet) 
		{
			hr = spOnGeomSet->QueryInterface(IID_CATIBodyRequest, (void**)&pCurBody);
			if (SUCCEEDED(hr) && NULL != pCurBody)
			{

				_spBackProfileSurface = this->RetrieveBackProfileSurface(pCurBody); //Store BackProfile Surface

				pCurBody->GetDirectBodies(ListResults);
				if (ListResults.Size() > 0)
				{
					for (int j = 1; j <= ListResults.Size(); j++)
					{
						CATBaseUnknown_var pCurBodyOnCircumGeomSet = ListResults[j];
						CATUnicodeString strAlias;
						CATIAlias_var spAlias = pCurBodyOnCircumGeomSet;
						if (!!spAlias && !!pCurBodyOnCircumGeomSet)
						{
							strAlias = spAlias->GetAlias();
							CATIBodyRequest_var spBodyReqOnCircumVent = pCurBodyOnCircumGeomSet;
							if (!!spBodyReqOnCircumVent && strAlias.SearchSubString("CircumVentSet") >= 0)
								listOfCircumGeomSet.Append(pCurBodyOnCircumGeomSet);
						}
					}
				}
				if (0 == listOfCircumGeomSet.Size())
				{
					CATDlgNotify * pErrPanel = new CATDlgNotify(pMainWindow, "Warning", CATDlgNfyOK | CATDlgNfyError | CATDlgWndModal);
					if (NULL == pErrPanel)
						return;

					// Set the text
					CATUnicodeString usWndTitle = "Warning Message", usMessage;

					usMessage.Append("Selected Geometrical Set do not have any 'CircumVentSet'.\nPlease select correct Geometrical Set or perform a 'Reset'.");
					//usMessage.Append("The Product with Name: \"" + strOnNameOfPrdToInstantiate + "\" and Rev: \" " + strOnRev + "does not exists in database.\n");


					pErrPanel->DisplayBlocked(usMessage, usWndTitle);

					pErrPanel->RequestDelayedDestruction(); pErrPanel = NULL;

				}
				pCurBody->Release(); pCurBody = NULL;
			}
		}
		else
		{
			

			CATDlgNotify * pErrPanel = new CATDlgNotify(pMainWindow, "Warning", CATDlgNfyOK | CATDlgNfyError | CATDlgWndModal);
			if (NULL == pErrPanel)
				return;

			// Set the text
			CATUnicodeString usWndTitle = "Warning Message", usMessage;

			usMessage.Append("Select Correct Ordered Geometrical Set\n");
			//usMessage.Append("The Product with Name: \"" + strOnNameOfPrdToInstantiate + "\" and Rev: \" " + strOnRev + "does not exists in database.\n");


			pErrPanel->DisplayBlocked(usMessage, usWndTitle);

			pErrPanel->RequestDelayedDestruction(); pErrPanel = NULL;
		}

		
	}

	if (listOfCircumGeomSet.Size() > 0)
	{
		this->CollectRevolveAndPointsInStrcut(listOfCircumGeomSet);
	}
}

void MRFCircumVentRefinementCmd::CollectRevolveAndPointsInStrcut(CATListValCATBaseUnknown_var spListOnCircumVentSet)
{
	_pListOfCircumVentCollStruct.RemoveAll();

	for (int i = 1; i <= spListOnCircumVentSet.Size(); i++)
	{
		CATListValCATBaseUnknown_var *spListOnFeaturesUnderCircumVentSet = NULL;
		CATIBodyRequest_var pCurBody = spListOnCircumVentSet[i];
		if (pCurBody != NULL_var)
		{
			_pCircumVentCollecvtion = new CircumVentCollection();

			_pCircumVentCollecvtion->spParentOfRevolve = pCurBody;
			_pCircumVentCollecvtion->nameOfCircumVentSet = MRFGenericUtils::GetAliasName(pCurBody);

			CATINavigateObject_var spNavigObject;
			spNavigObject = pCurBody;
			if (!!spNavigObject)
				spListOnFeaturesUnderCircumVentSet = spNavigObject->GetChildren();
			if (!spListOnFeaturesUnderCircumVentSet)
				continue;

			if (spListOnFeaturesUnderCircumVentSet->Size() > 0)
			{
				for (int j = 1; j <= spListOnFeaturesUnderCircumVentSet->Size() && _pCircumVentCollecvtion != NULL; j++)
				{
					CATBaseUnknown_var pCurBodyOnFeatures = (*spListOnFeaturesUnderCircumVentSet)[j];
					CATUnicodeString strAlias;
					CATIAlias_var spAlias = pCurBodyOnFeatures;
					if (!!spAlias && !!pCurBodyOnFeatures)
					{
						strAlias = spAlias->GetAlias();


						CATIGSMUseIntersect_var spGSMUseIntersect = pCurBodyOnFeatures;
						if (!!spGSMUseIntersect)
							_pCircumVentCollecvtion->listOfPointsUnderRevolve.Append(pCurBodyOnFeatures);
						else
						{
							CATIGSMUseRevol_var spGSMUseRevol = pCurBodyOnFeatures;

							if (!!spGSMUseRevol && CheckIfShowMode(spGSMUseRevol, spGSMUseRevol))
							{
								_pCircumVentCollecvtion->spOnRevolve = spGSMUseRevol;
																
							}
							else
							{
								delete _pCircumVentCollecvtion; _pCircumVentCollecvtion = NULL;
								break;
							}
								
						}


					}


				}

				if(_pCircumVentCollecvtion)
					_pListOfCircumVentCollStruct.Append(_pCircumVentCollecvtion);
			}
			pCurBody->Release(); pCurBody = NULL;
		}
	}

}

void MRFCircumVentRefinementCmd::PopulateMultiList(const CATListPV &strcutListOfCircumVentColl)
{
	static int count  = 1;
	double toleranceVal = this->GetToleranceValue();

	if (strcutListOfCircumVentColl.Size() > 0 && count <= strcutListOfCircumVentColl.Size())
	{
		CircumVentCollection *pCircumVentCollFirstRef = (CircumVentCollection*)strcutListOfCircumVentColl[count];
		CATBaseUnknown_var spOnRevolveToCompare;
		CATBody_var spBodyOnRevol;
		if (pCircumVentCollFirstRef)
		{
			spOnRevolveToCompare = pCircumVentCollFirstRef->spOnRevolve;

			/*if (!!spOnRevolveToCompare)
				MRFGenericUtils::GetBodyOfObject(spOnRevolveToCompare, spBodyOnRevol);*/

		}

		if (!!spOnRevolveToCompare && CheckIfShowMode(spOnRevolveToCompare, spOnRevolveToCompare))
		{
			
			CircumVentCollection *pCircumVentCollSecondRef = NULL;
			CATBaseUnknown_var spOnRevolForMinDis;
			CATBody_var spBodyOnRevolForMinDis;
			double minDist = 10e100;
			bool isAnyOneRevolveWithinTolerance = false;
			for (int i = count + 1; i <= strcutListOfCircumVentColl.Size(); i++)
			{
				minDist = 10e100;
				bool minDistFound = false;
				pCircumVentCollSecondRef = (CircumVentCollection*)strcutListOfCircumVentColl[i];
				if (!!pCircumVentCollSecondRef)
				{
					spOnRevolForMinDis = pCircumVentCollSecondRef->spOnRevolve;

				/*	if (!!spOnRevolForMinDis)
						MRFGenericUtils::GetBodyOfObject(spOnRevolForMinDis, spBodyOnRevolForMinDis);*/

					if (!!spOnRevolForMinDis && CheckIfShowMode(spOnRevolForMinDis, spOnRevolForMinDis))
					{
						//minDist = _pMRFCircumVentRefinementOperations->GetMinDistBetwnTwoRevolv(spBodyOnRevol, spBodyOnRevolForMinDis);
						CATIMmiMechanicalFeature_var spMechFeatOnRevol_1 = spOnRevolveToCompare;
						CATIMmiMechanicalFeature_var spMechFeatOnRevol_2 = spOnRevolForMinDis;
						CATIMeasurableInContext_var spMeasureInContext1 = spMechFeatOnRevol_1;
						CATIMeasurable_var spMeasureInContext2 = spMechFeatOnRevol_2;
						if (!!spMeasureInContext1 && !!spMeasureInContext2)
						{
							CATMathPoint pointOnSource, pOintOnTarghet;
							CATMathAxis pAxis;
							spMeasureInContext1->MinimumDistance(spMeasureInContext2, pAxis, minDist, pointOnSource, pOintOnTarghet);
							minDistFound = true;
							

						}
					
					}
					else
					{
						spOnRevolForMinDis = NULL;
						pCircumVentCollSecondRef = NULL;

						continue;
					}
				}


				if (minDist < toleranceVal && minDistFound)
				{
					_pMultiListValuesToSet = new MultiListValuesToSet();
					_pMultiListValuesToSet->CircumVent_1 = MRFGenericUtils::GetAliasName(pCircumVentCollFirstRef->spParentOfRevolve);
					_pMultiListValuesToSet->CircumVent_2 = MRFGenericUtils::GetAliasName(pCircumVentCollSecondRef->spParentOfRevolve);
					_pMultiListValuesToSet->Revolve_1 = MRFGenericUtils::GetAliasName(spOnRevolveToCompare);
					_pMultiListValuesToSet->Revolve_2 = MRFGenericUtils::GetAliasName(spOnRevolForMinDis);
					_pMultiListValuesToSet->listOfPointsUnderRevolve_1 = pCircumVentCollFirstRef->listOfPointsUnderRevolve;
					_pMultiListValuesToSet->listOfPointsUnderRevolve_2 = pCircumVentCollSecondRef->listOfPointsUnderRevolve;
					_pMultiListValuesToSet->noOfPointsIn_1 = pCircumVentCollFirstRef->listOfPointsUnderRevolve.Size();
					_pMultiListValuesToSet->noOfPointsIn_2 = pCircumVentCollSecondRef->listOfPointsUnderRevolve.Size();
					_pMultiListValuesToSet->spOnRevolveOfCircVent_1 = spOnRevolveToCompare;
					_pMultiListValuesToSet->spOnRevolveOfCircVent_2 = spOnRevolForMinDis;
					_pMultiListValuesToSet->spOnCircVent_1 = pCircumVentCollFirstRef->spParentOfRevolve;
					_pMultiListValuesToSet->spOnCircVent_2 = pCircumVentCollSecondRef->spParentOfRevolve;
					
					
					_pListOfMultiListValuesToSetStruct.Append(_pMultiListValuesToSet);
					_CircumVentNotToIncludeUnderRegularVent.Append(pCircumVentCollFirstRef->nameOfCircumVentSet);
					_CircumVentNotToIncludeUnderRegularVent.Append(pCircumVentCollSecondRef->nameOfCircumVentSet);

					isAnyOneRevolveWithinTolerance = true;
				}

				//Following Variables are repointed in for loop------------STARTS
				spBodyOnRevolForMinDis = NULL;
				spOnRevolForMinDis = NULL;
				pCircumVentCollSecondRef = NULL;
				//Following Variables are repointed in for loop------------ENDS

			}

			if (isAnyOneRevolveWithinTolerance == false)
			{
				int indexFound = 0;
				if (!_CircumVentNotToIncludeUnderRegularVent.Locate(pCircumVentCollFirstRef->nameOfCircumVentSet, 1))
				{
					_RegularVentCollection.Append(pCircumVentCollFirstRef->nameOfCircumVentSet);
					if (!!pCircumVentCollFirstRef->spOnRevolve && _pMRFCircumVentRefinementOperations)
						_pMRFCircumVentRefinementOperations->SetColorProperties(pCircumVentCollFirstRef->spOnRevolve, "Yellow");
				}

			}
		}
		else
		{
			count++;
			PopulateMultiList(strcutListOfCircumVentColl);		
		}

	}
	else
	{
		count = 1;
		return;
	}

	count++;
	PopulateMultiList(strcutListOfCircumVentColl);
	
}

double MRFCircumVentRefinementCmd::GetToleranceValue()
{
	double val = 10e100;
	if (_pMRFCircumVentRefCmdDlg)
	{
		val =  _pMRFCircumVentRefCmdDlg->GetSpinnerTolerance()->GetCurrentValue();
	}

	return val;
}

void MRFCircumVentRefinementCmd::ManageMultiListData()
{
	CATDlgMultiList *_pMultiListOfCircumVentData = NULL;

	if (_pMRFCircumVentRefCmdDlg && _pListOfMultiListValuesToSetStruct.Size()>0)
	{
		_pMultiListOfCircumVentData = _pMRFCircumVentRefCmdDlg->GetMultiListCircumVentSetCollection();

		if (_pMultiListOfCircumVentData)
		{
			_pMultiListOfCircumVentData->ClearLine();

			for (int i = 1; i <= _pListOfMultiListValuesToSetStruct.Size(); i++)
			{
				MultiListValuesToSet *pMultiListRowVal = (MultiListValuesToSet*)_pListOfMultiListValuesToSetStruct[i];
				if (pMultiListRowVal)
				{
					int noOfPoint1 = pMultiListRowVal->noOfPointsIn_1;
					int noOfPoint2 = pMultiListRowVal->noOfPointsIn_2;
					CATUnicodeString point1, point2;
					point1.BuildFromNum(noOfPoint1);
					point2.BuildFromNum(noOfPoint2);

					_pMultiListOfCircumVentData->SetColumnItem(0, pMultiListRowVal->Revolve_1, i, CATDlgDataModify);
					_pMultiListOfCircumVentData->SetColumnItem(1, pMultiListRowVal->Revolve_2, i, CATDlgDataModify);
					_pMultiListOfCircumVentData->SetColumnItem(2, point1, i, CATDlgDataModify);
					_pMultiListOfCircumVentData->SetColumnItem(3, point2, i, CATDlgDataModify);
				}
			}
		}
	}
	else
	{
		_pMultiListOfCircumVentData = _pMRFCircumVentRefCmdDlg->GetMultiListCircumVentSetCollection();
		if (_pMultiListOfCircumVentData)
			_pMultiListOfCircumVentData->ClearLine();
	}

}

